-- super-coder skills seed ŌĆö GENERATED by scripts/seed_skills.py.
-- System content: the catalogue propagates to every fork. Idempotent and
-- ID-STABLE: retires names no longer authored, then UPSERTs each skill by
-- name ŌĆö so skill_id never churns and shell_skills grants stay valid when
-- this re-runs as the update catalogue-sync. Do not hand-edit; author
-- assets/skills/<name>/SKILL.md then `./sc seed-skills`.

BEGIN;

-- Retire any catalogue skill that is no longer authored (soft-delete;
-- keeps the row + id so a re-add is stable and grants are recoverable).
UPDATE skills SET is_deleted=1 WHERE name NOT IN ('api-design', 'blueprint', 'bootstrap', 'database-migrations', 'db_map', 'docs', 'flags', 'git', 'memory', 'onboard', 'self_update', 'snapshot', 'surface_catalogue');

INSERT INTO skills (name, description, category, command, common, content, is_deleted) VALUES (
  'api-design',
  'REST/HTTP API design patterns ŌĆö resource naming, status codes, pagination, filtering, errors, versioning, idempotency. Use when designing or reviewing API endpoints.',
  'craft',
  NULL,
  0,
  '# api-design ŌĆö designing & reviewing HTTP APIs

Catalogue skill (opt-in). Reach for it when shaping or reviewing an endpoint.

## Resources & methods
- Name resources as **plural nouns**, not verbs: `/users`, `/users/{id}/orders`.
- `GET` read (safe, idempotent) ┬Ę `POST` create / non-idempotent action ┬Ę
  `PUT` full replace (idempotent) ┬Ę `PATCH` partial update ┬Ę `DELETE` remove.
- Nest only one level deep; beyond that, link by id.

## Status codes
- `200` ok ┬Ę `201` created (+ `Location`) ┬Ę `204` no content.
- `400` bad input ┬Ę `401` unauth ┬Ę `403` forbidden ┬Ę `404` not found ┬Ę
  `409` conflict ┬Ę `422` validation ┬Ę `429` rate-limited.
- `5xx` = server''s fault; never use it for client errors.

## Payloads
- Consistent error shape: `{ "error": { "code", "message", "details" } }`.
- **Pagination**: cursor-based for large/changing sets (`?cursor=&limit=`),
  return `next_cursor`; offset only for small stable sets.
- **Filtering/sorting**: explicit query params (`?status=open&sort=-created`);
  whitelist fields ŌĆö never interpolate them into a query.
- Timestamps ISO-8601 UTC; ids opaque strings.

## Robustness
- **Idempotency**: make retries safe ŌĆö `PUT`/`DELETE` naturally; for `POST`,
  accept an idempotency key.
- **Versioning**: prefix (`/v1/ŌĆ”`) or header; add fields backward-compatibly,
  never repurpose one.
- Validate at the boundary; reject unknown fields or ignore them ŌĆö decide and
  document. Don''t leak internals (stack traces, SQL) in errors.

## Review lens
Does each endpoint do one thing? Right method + status? Errors uniform? Inputs
validated/whitelisted? Retries safe? Breaking change hiding in a "small" tweak?',
  0
)
